<template>
  <div>
    <el-breadcrumb separator="/" style="padding-left: 10px;padding-bottom: 10px;font-size: 12px">
      <el-breadcrumb-item :to="{ path: '/main' }">首页</el-breadcrumb-item>
      <el-breadcrumb-item>系统管理</el-breadcrumb-item>
      <el-breadcrumb-item>公司企业信息管理</el-breadcrumb-item>
    </el-breadcrumb>

    <el-card class="box-card">
      <el-form :inline="true" :model="userVo" class="demo-form-inline">
        <el-form-item label="企业名称" label-width="70px">
          <el-input clearable v-model="userVo.cname" placeholder="请输入企业名称"></el-input>
        </el-form-item>
        <el-form-item label="电话" label-width="70px">
          <el-input clearable v-model="userVo.ctel" placeholder="请输入电话"></el-input>
        </el-form-item>
        <el-form-item label="服务范围" label-width="70px">
          <el-input clearable v-model="userVo.cmajor" placeholder="请输入服务范围"></el-input>
        </el-form-item>
        <el-form-item label="所在地址" label-width="70px">
          <el-input clearable v-model="userVo.cattr" placeholder="请输入所在地址"></el-input>
        </el-form-item>
        <el-form-item style="margin-left: 10px">
          <el-button icon="el-icon-refresh" @click="resetUserVo">重置</el-button>
          <el-button type="primary" icon="el-icon-search" @click="getUserList">查询</el-button>
          <el-button type="success" icon="el-icon-plus" @click="show">添加</el-button>
        </el-form-item>
      </el-form>
      <el-table
        :data="userList"
        border
        max-height="400"
        style="width: 100%;">
        <el-table-column
          prop="id"
          label="#"
          type="index"
          width="50">
        </el-table-column>

        <el-table-column width="100">
          <template slot-scope="scope">
            <img v-if="scope.row.imgtype=='image/jpeg'"
                 :src="require('../../assets/uploadImgs/'+scope.row.cimg)"
                 width="40" height="40" class="head_pic"/>
            <img v-else-if="scope.row.imgtype=='image/png'"
                 :src="require('../../assets/uploadImgs/'+scope.row.cimg)"
                 width="40" height="40" class="head_pic"/>
          </template>
        </el-table-column>

        <el-table-column
          prop="cname"
          label="企业名称"
          width="180">
        </el-table-column>

        <el-table-column
          prop="cpwd"
          label="密码"
          width="120">
        </el-table-column>
        <el-table-column
          sortable
          prop="ctel"
          label="电话"
          width="100">
        </el-table-column>
        <el-table-column
          prop="cstaffnums"
          label="员工人数"
          width="100">
        </el-table-column>
        <el-table-column
          prop="cmajor"
          label="服务范围"
          width="300">
        </el-table-column>
        <el-table-column
          prop="cattr"
          label="所在地址"
          width="250">
        </el-table-column>
        <el-table-column
          prop="cstatus"
          label="状态"
          width="180">
        </el-table-column>
        <el-table-column
          label="操作" width="250">
          <template slot-scope="scope">
            <el-button type="danger" size="mini"  v-if="scope.row.cflag == 0 || scope.row.cflag == 2"
                       icon="el-icon-circle-check" @click="passDatas(scope.row.id)" title="通过"></el-button>
            <el-button type="danger" size="mini"  v-if="scope.row.cflag == 0 || scope.row.cflag == 2"
                       icon="el-icon-remove-outline" @click="nopassDatas(scope.row.id)" title="不通过"></el-button>
            <el-button type="primary" size="mini" icon="el-icon-edit" @click="userEdit(scope.row)" title="编辑"></el-button>
            <el-button type="danger" size="mini" icon="el-icon-delete" @click="deleteUsers(scope.row.id)" title="删除"></el-button>
          </template>
        </el-table-column>
      </el-table>
      <el-pagination
        style="padding-top: 15px"
        @size-change="handleSizeChange"
        @current-change="handleCurrentChange"
        :current-page="current"
        :page-sizes="[6, 10, 20, 30]"
        :page-size="size"
        layout="total, sizes, prev, pager, next, jumper"
        :total="total">
      </el-pagination>

      <CompanysAdd :addOrUpdateVisible="addOrUpdateVisible" @changeShow="showAddOrUpdate" ref="addOrUpdateRef"></CompanysAdd>
      <CompanysEdit :addOrUpdateVisible="editOrUpdateVisible" @changeShow="showEidtOrUpdate" ref="eidtOrUpdateRef"></CompanysEdit>
    </el-card>
  </div>

</template>

<script>
  import { findCompanysList,findCompanysById,deleteCompanys,passCompanys,nopassCompanys } from '../../api/companys';

  import CompanysAdd from './CompanysAdd';
  import CompanysEdit from './CompanysEdit';

  export default {
    name: 'Companys',
    data() {
      return {
        userVo: {
          cname: '',
          ctel: '',
          cmajor: '',
          cattr: ''
        },
        addOrUpdateVisible: false,
        editOrUpdateVisible: false,
        userList: [],
        size: 6,
        total: 100,
        current: 1
      };
    },
    components: {
      CompanysEdit,
      CompanysAdd
    },
    created(){
      this.getUserList();
    },
    methods: {
      onSubmit() {
        console.log('submit!');
      },
      handleSizeChange(val) {
        this.size = val;
        this.getUserList();
      },
      handleCurrentChange(val) {
        this.current = val;
        this.getUserList();
      },
      async getUserList(){
        const { data } = await findCompanysList(this.current,this.size,this.userVo);
        this.userList = data.data.records;
        this.total = data.data.total;
      },
      resetUserVo(){
        this.userVo.cname = '';
        this.userVo.ctel = '';
        this.userVo.cmajor = '';
        this.userVo.cattr= '';
        this.getUserList();
      },
      show(){
        this.addOrUpdateVisible = true;
      },
      passDatas(id){
        var that = this;
        this.$confirm('此操作将通过, 是否继续?', '提示', {
          confirmButtonText: '确定',
          cancelButtonText: '取消',
          type: 'warning'
        }).then(() => {
          passCompanys(id);
          this.$message({
            type: 'success',
            message: '通过成功!'
          });
          that.getUserList();
        }).catch(() => {
          this.$message({
            type: 'info',
            message: '通过失败'
          });
        });
      },

      nopassDatas(id){
        var that = this;
        this.$confirm('此操作将不通过, 是否继续?', '提示', {
          confirmButtonText: '确定',
          cancelButtonText: '取消',
          type: 'warning'
        }).then(() => {
          nopassCompanys(id);
          this.$message({
            type: 'success',
            message: '不通过成功!'
          });
          that.getUserList();
        }).catch(() => {
          this.$message({
            type: 'info',
            message: '失败'
          });
        });
      },
      deleteUsers(id){
        var that = this;
        this.$confirm('此操作将永久删除该公司企业, 是否继续?', '提示', {
          confirmButtonText: '确定',
          cancelButtonText: '取消',
          type: 'warning'
        }).then(() => {
          deleteCompanys(id);
          this.$message({
            type: 'success',
            message: '删除成功!'
          });
          that.getUserList();
        }).catch(() => {
          this.$message({
            type: 'info',
            message: '已取消删除'
          });
        });
      },
       userEdit(row){
        var that = this;
         this.editOrUpdateVisible = true;
        this.$nextTick(() => {
            that.$refs.eidtOrUpdateRef.dataInit(row);
        });
         this.getUserList();
        console.log(this.userEdit);
      },
      showAddOrUpdate(data){
        if(data === 'false'){
          this.addOrUpdateVisible = false;
        }else{
          this.addOrUpdateVisible = true;
        }
        this.getUserList();
      },
      showEidtOrUpdate(data){
        if(data === 'false'){
          this.editOrUpdateVisible = false;
        }else{
          this.editOrUpdateVisible = true;
        }
        this.getUserList();
      }
    }
  };
</script>

<style scoped>

</style>
